DOCKER_IMAGE_TAG="${DOCKER_IMAGE_TAG:-latest}"
ASSUME_ROLE_ARN="${ASSUME_ROLE_ARN:-}"
MFA_SERIAL="${MFA_SERIAL:-}"
SESSION_DURATION="${SESSION_DURATION:-3600}"
ROLLBACK_ON_FAILURE="${ROLLBACK_ON_FAILURE:-true}"
DRY_RUN="${DRY_RUN:-false}"

log() {
    local level="$1"
    shift
    local message="$*"
    local timestamp=$(date '+%Y-%m-%d %H:%M:%S')
    echo "[${timestamp}] [${level}] ${message}" | tee -a "${LOG_FILE}"
}

error_exit() {
    log "ERROR" "$1"
    exit 1
}

check_dependencies() {
    log "INFO" "Checking dependencies..."
    
    local deps=("aws" "jq")
    
    if [[ "${DEPLOYMENT_TYPE}" == "docker" ]] || [[ "${DEPLOYMENT_TYPE}" == "ecs" ]]; then
        deps+=("docker")
    fi
    
    for dep in "${deps[@]}"; do
        if ! command -v "${dep}" &> /dev/null; then
            error_exit "Required dependency '${dep}' not found. Please install it first."
        fi
    done
    
    log "INFO" "All dependencies satisfied"
}

is_ci_environment() {
    [[ -n "${CI:-}" ]] || [[ -n "${JENKINS_HOME:-}" ]] || [[ -n "${GITHUB_ACTIONS:-}" ]] || [[ -n "${GITLAB_CI:-}" ]] || [[ -n "${CIRCLECI:-}" ]]
}

get_aws_account_id() {
    aws sts get-caller-identity --query Account --output text 2>/dev/null || echo ""
}

authenticate_aws() {
    log "INFO" "Authenticating with AWS..."
    
    if is_ci_environment; then
        log "INFO" "CI environment detected"
        
        if [[ -n "${AWS_ACCESS_KEY_ID:-}" ]] && [[ -n "${AWS_SECRET_ACCESS_KEY:-}" ]]; then
            log "INFO" "Using AWS credentials from environment variables"
        elif [[ -n "${AWS_WEB_IDENTITY_TOKEN_FILE:-}" ]] && [[ -n "${AWS_ROLE_ARN:-}" ]]; then
            log "INFO" "Using AWS Web Identity Token for authentication"
        else
            error_exit "No valid AWS credentials found in CI environment"
        fi
    else
        log "INFO" "Local development environment detected"
        
        if [[ ! -f "${HOME}/.aws/credentials" ]] && [[ ! -f "${HOME}/.aws/config" ]]; then
            error_exit "AWS credentials not configured. Run 'aws configure' first."
        fi
    fi
    
    if [[ -n "${ASSUME_ROLE_ARN}" ]]; then
        assume_role
    fi
    
    local account_id=$(get_aws_account_id)
    if [[ -z "${account_id}" ]]; then
        error_exit "Failed to authenticate with AWS"
    fi
    
    log "INFO" "Successfully authenticated with AWS Account: ${account_id}"
    log "INFO" "Using region: ${AWS_REGION}"
}

assume_role() {
    log "INFO" "Assuming role: ${ASSUME_ROLE_ARN}"
    
    local session_name="deployment-session-$(date +%s)"
    local assume_role_cmd="aws sts assume-role --role-arn ${ASSUME_ROLE_ARN} --role-session-name ${session_name} --duration-seconds ${SESSION_DURATION}"
    
    if [[ -n "${MFA_SERIAL}" ]]; then
        if is_ci_environment; then
            error_exit "MFA is not supported in CI/CD environments"
        fi
        
        read -rp "Enter MFA token code: " mfa_token
        assume_role_cmd="${assume_role_cmd} --serial-number ${MFA_SERIAL} --token-code ${mfa_token}"
    fi
    
    local credentials
    credentials=$(eval "${assume_role_cmd}" 2>/dev/null) || error_exit "Failed to assume role"
    
    export AWS_ACCESS_KEY_ID=$(echo "${credentials}" | jq -r '.Credentials.AccessKeyId')
    export AWS_SECRET_ACCESS_KEY=$(echo "${credentials}" | jq -r '.Credentials.SecretAccessKey')
    export AWS_SESSION_TOKEN=$(echo "${credentials}" | jq -r '.Credentials.SessionToken')
    
    log "INFO" "Successfully assumed role"
}

validate_deployment_config() {
    log "INFO" "Validating deployment configuration..."
    
    case "${DEPLOYMENT_TYPE}" in
        s3)
            [[ -z "${S3_BUCKET}" ]] && error_exit "S3_BUCKET is required for S3 deployment"
            [[ ! -d "${BUILD_DIR}" ]] && error_exit "Build directory '${BUILD_DIR}' not found"
            ;;
        lambda)
            [[ -z "${LAMBDA_FUNCTION}" ]] && error_exit "LAMBDA_FUNCTION is required for Lambda deployment"
            ;;
        ecs)
            [[ -z "${ECR_REPOSITORY}" ]] && error_exit "ECR_REPOSITORY is required for ECS deployment"
            [[ -z "${ECS_CLUSTER}" ]] && error_exit "ECS_CLUSTER is required for ECS deployment"
            [[ -z "${ECS_SERVICE}" ]] && error_exit "ECS_SERVICE is required for ECS deployment"
            ;;
        docker)
            [[ -z "${ECR_REPOSITORY}" ]] && error_exit "ECR_REPOSITORY is required for Docker deployment"
            ;;
        *)
            error_exit "Invalid DEPLOYMENT_TYPE: ${DEPLOYMENT_TYPE}. Supported types: s3, lambda, ecs, docker"
            ;;
    esac
    
    log "INFO" "Configuration validated successfully"
}

create_backup() {
    local backup_type="$1"
    log "INFO" "Creating backup for ${backup_type}..."
    
    case "${backup_type}" in
        s3)
            local timestamp=$(date +%Y%m%d-%H%M%S)
            local backup_prefix="backups/${DEPLOYMENT_ENV}/${timestamp}"
            
            aws s3 sync "s3://${S3_BUCKET}/" "s3://${S3_BUCKET}/${backup_prefix}/" \
                --region "${AWS_REGION}" \
                --exclude "${backup_prefix}/*" 2>&1 | tee -a "${LOG_FILE}" || true
            
            echo "${backup_prefix}" > /tmp/backup-location.txt
            log "INFO" "Backup created at: s3://${S3_BUCKET}/${backup_prefix}/"
            ;;
        lambda)
            local version=$(aws lambda publish-version \
                --function-name "${LAMBDA_FUNCTION}" \
                --region "${AWS_REGION}" \
                --query 'Version' \
                --output text 2>/dev/null || echo "")
            
            if [[ -n "${version}" ]]; then
                echo "${version}" > /tmp/backup-version.txt
                log "INFO" "Lambda version ${version} published as backup"
            fi
            ;;
        ecs)
            local task_def=$(aws ecs describe-services \
                --cluster "${ECS_CLUSTER}" \
                --services "${ECS_SERVICE}" \
                --region "${AWS_REGION}" \
                --query 'services[0].taskDefinition' \
                --output text 2>/dev/null || echo "")
            
            if [[ -n "${task_def}" ]]; then
                echo "${task_def}" > /tmp/backup-taskdef.txt
                log "INFO" "Current task definition saved: ${task_def}"
            fi
            ;;
    esac
}

deploy_to_s3() {
    log "INFO" "Starting S3 deployment to bucket: ${S3_BUCKET}"
    
    if [[ "${ROLLBACK_ON_FAILURE}" == "true" ]]; then
        create_backup "s3"
    fi
    
    local sync_cmd="aws s3 sync ${BUILD_DIR}/ s3://${S3_BUCKET}/ --region ${AWS_REGION} --delete"
    
    if [[ "${DRY_RUN}" == "true" ]]; then
        sync_cmd="${sync_cmd} --dryrun"
        log "INFO" "DRY RUN MODE - No actual changes will be made"
    fi
    
    eval "${sync_cmd}" 2>&1 | tee -a "${LOG_FILE}" || {
        if [[ "${ROLLBACK_ON_FAILURE}" == "true" ]]; then
            rollback_s3_deployment
        fi
        error_exit "S3 deployment failed"
    }
    
    if aws s3api get-bucket-website --bucket "${S3_BUCKET}" --region "${AWS_REGION}" &>/dev/null; then
        log "INFO" "Invalidating CloudFront cache if applicable..."
        local distribution_id=$(aws cloudfront list-distributions \
            --query "DistributionList.Items[?Origins.Items[?DomainName=='${S3_BUCKET}.s3.amazonaws.com']].Id | [0]" \
            --output text 2>/dev/null || echo "")
        
        if [[ -n "${distribution_id}" ]] && [[ "${distribution_id}" != "None" ]]; then
            if [[ "${DRY_RUN}" != "true" ]]; then
                aws cloudfront create-invalidation \
                    --distribution-id "${distribution_id}" \
                    --paths "/*" 2>&1 | tee -a "${LOG_FILE}"
                log "INFO" "CloudFront invalidation created for distribution: ${distribution_id}"
            fi
        fi
    fi
    
    log "INFO" "S3 deployment completed successfully"
}

rollback_s3_deployment() {
    log "WARN" "Rolling back S3 deployment..."
    
    if [[ ! -f /tmp/backup-location.txt ]]; then
        log "ERROR" "No backup location found, cannot rollback"
        return 1
    fi
    
    local backup_prefix=$(cat /tmp/backup-location.txt)
    
    aws s3 sync "s3://${S3_BUCKET}/${backup_prefix}/" "s3://${S3_BUCKET}/" \
        --region "${AWS_REGION}" \
        --delete 2>&1 | tee -a "${LOG_FILE}"
    
    log "INFO" "Rollback completed"
}

build_and_push_docker_image() {
    log "INFO" "Building and pushing Docker image..."
    
    local account_id=$(get_aws_account_id)
    local ecr_url="${account_id}.dkr.ecr.${AWS_REGION}.amazonaws.com"
    local full_image_name="${ecr_url}/${ECR_REPOSITORY}:${DOCKER_IMAGE_TAG}"
    
    aws ecr get-login-password --region "${AWS_REGION}" | \
        docker login --username AWS --password-stdin "${ecr_url}" 2>&1 | tee -a "${LOG_FILE}" || \
        error_exit "Failed to authenticate with ECR"
    
    if [[ ! -f Dockerfile ]]; then
        error_exit "Dockerfile not found in current directory"
    fi
    
    if [[ "${DRY_RUN}" == "true" ]]; then
        log "INFO" "DRY RUN MODE - Skipping Docker build and push"
        echo "${full_image_name}"
        return 0
    fi
    
    docker build -t "${ECR_REPOSITORY}:${DOCKER_IMAGE_TAG}" . 2>&1 | tee -a "${LOG_FILE}" || \
        error_exit "Docker build failed"
    
    docker tag "${ECR_REPOSITORY}:${DOCKER_IMAGE_TAG}" "${full_image_name}" 2>&1 | tee -a "${LOG_FILE}"
    
    docker push "${full_image_name}" 2>&1 | tee -a "${LOG_FILE}" || \
        error_exit "Failed to push Docker image to ECR"
    
    log "INFO" "Docker image pushed successfully: ${full_image_name}"
    echo "${full_image_name}"
}

